using UnityEngine;

/// <summary>
/// "Tela de morte" (Tarefa #16 — verificação final; estendido na Tarefa "Morte
/// e checkpoints"): liga-se a PlayerProgress.OnHeartsDepleted (disparado
/// quando "currentHearts" chega a 0 — ver PlayerCombat.TryDamagePlayer →
/// PlayerProgress.Damage) e conduz a sequência de morte/reaparecimento:
///
/// 1) Bloqueia o movimento (motor.SetMovementLocked) e pára o Rigidbody2D.
/// 2) Regista a morte na área actual (PlayerProgress.RegisterDeath —
///    WorldState.CurrentArea).
/// 3) Toca a animação/SFX de morte (trigger "Death" no Animator).
/// 4) Pede a DeathScreenUI para mostrar o overlay; quando este estiver
///    totalmente visível, chama <see cref="Respawn"/>: recupera a vida ao
///    máximo, reposiciona o player (checkpoint temporário — Checkpoint.cs —
///    se existir para a área actual, senão o último Refúgio Seguro —
///    SafeHaven/lastCheckpointId) e faz reset selectivo dos inimigos da cena
///    (chefes EnemyMultiPartBoss + EnemyRespawn modo "Comum"), preservando
///    inimigos "Especiais"/MiniBoss derrotados permanentemente e variáveis
///    globais (puzzles/NPCs resgatados).
/// 5) Desbloqueia o movimento depois do overlay desaparecer.
///
/// Prevenção de morte repetida durante o fade: enquanto "isDead" estiver
/// activo (entre o primeiro OnHeartsDepleted e o fim de Respawn), chamadas
/// adicionais a OnHeartsDepleted são ignoradas — evita registar várias mortes/
/// tocar SFX repetido se o jogador continuar a sofrer dano com 0 corações
/// durante o fade da DeathScreenUI.
///
/// Provação de Apolo (Sistema de Desafios, Tarefa #15): se
/// <see cref="ChallengeManager.IsApoloTrialActive"/> estiver activo no momento
/// da morte, NÃO segue o fluxo normal (sem <see cref="PlayerProgress.RegisterDeath"/>,
/// sem checkpoint/Refúgio Seguro) — em vez disso <see cref="RespawnApoloTrial"/>
/// recupera a vida e pede ao ChallengeManager para reiniciar a prova do início
/// (<see cref="ChallengeManager.RestartApoloTrial"/>: cronómetro, objectivos,
/// condições de falha e reposicionamento na entrada da prova).
/// </summary>
[RequireComponent(typeof(PlayerMotor2D), typeof(Rigidbody2D))]
public class PlayerDeathHandler : MonoBehaviour
{
    [Header("Som")]
    [SerializeField] private AudioClip deathSfx;

    private PlayerMotor2D motor;
    private Rigidbody2D rb;
    private AbilityRouter abilityRouter;
    private bool isDead;

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
        rb = GetComponent<Rigidbody2D>();
        abilityRouter = GetComponent<AbilityRouter>();
    }

    private void OnEnable()
    {
        if (PlayerProgress.Instance != null)
            PlayerProgress.Instance.OnHeartsDepleted += OnHeartsDepleted;
    }

    private void OnDisable()
    {
        if (PlayerProgress.Instance != null)
            PlayerProgress.Instance.OnHeartsDepleted -= OnHeartsDepleted;
    }

    private void OnHeartsDepleted()
    {
        // Prevenção de morte repetida durante o fade (ver resumo da classe):
        // ignora novos triggers enquanto a sequência de morte/respawn anterior
        // ainda não terminou.
        if (isDead) return;
        isDead = true;

        // Interrompe qualquer habilidade "com estado" activa (escalar, dash,
        // balanço, língua, escudo, carregar objecto, ...) — item 8 da
        // auditoria: morrer a meio de uma destas deixava o player preso num
        // estado inconsistente após o respawn (gravidade/locks não restaurados).
        if (abilityRouter != null)
            abilityRouter.CancelAll(AbilityCancelReason.Death);

        // Tarefa "Itens Consumíveis": efeitos temporários (escudo, velocidade,
        // invisibilidade, etc.) não devem sobreviver à morte/reaparecimento.
        GetComponent<PlayerConsumableEffects>()?.ClearAll();

        motor.SetMovementLocked(true, this);
        motor.SetDashing(false);
        rb.linearVelocity = Vector2.zero;

        if (motor.Anim != null) motor.Anim.SetTrigger("Death");
        AudioManager.Instance?.PlaySE(deathSfx);

        bool apoloRestart = ChallengeManager.Instance != null && ChallengeManager.Instance.IsApoloTrialActive;

        if (!apoloRestart)
        {
            var area = WorldState.Instance != null ? WorldState.Instance.CurrentArea : null;
            if (area != null) PlayerProgress.Instance?.RegisterDeath(area);
        }

        System.Action onComplete = apoloRestart ? (System.Action)RespawnApoloTrial : Respawn;

        if (DeathScreenUI.Instance != null)
            DeathScreenUI.Instance.PlayDeathSequence(onComplete);
        else
            onComplete();
    }

    /// <summary>
    /// Recupera a vida ao máximo, reposiciona o player (ver
    /// <see cref="ResolveCheckpointPosition"/>) e faz o reset selectivo dos
    /// inimigos da cena (ver <see cref="ResetSceneEnemies"/>).
    /// </summary>
    private void Respawn()
    {
        var progress = PlayerProgress.Instance;
        if (progress != null) progress.Heal(progress.maxHearts);

        if (ResolveCheckpointPosition(out Vector2 position))
        {
            rb.position = position;
            rb.linearVelocity = Vector2.zero;
        }

        ResetSceneEnemies();

        motor.SetMovementLocked(false, this);
        isDead = false;
    }

    /// <summary>
    /// Reaparecimento da Provação de Apolo (Sistema de Desafios, Tarefa #15):
    /// em vez do fluxo normal de morte (checkpoint/Refúgio Seguro, contagem de
    /// mortes da área), recupera a vida ao máximo, faz o mesmo reset selectivo
    /// de inimigos do respawn normal (<see cref="ResetSceneEnemies"/>) e pede ao
    /// ChallengeManager para reiniciar a prova do início — cronómetro,
    /// objectivos, condições de falha e reposicionamento na entrada da prova
    /// (<see cref="ChallengeManager.RestartApoloTrial"/>).
    /// </summary>
    private void RespawnApoloTrial()
    {
        var progress = PlayerProgress.Instance;
        if (progress != null) progress.Heal(progress.maxHearts);

        ChallengeManager.Instance?.RestartApoloTrial();
        ResetSceneEnemies();

        motor.SetMovementLocked(false, this);
        isDead = false;
    }

    /// <summary>
    /// Determina a posição de reaparecimento, por ordem de prioridade:
    /// 1) Checkpoint temporário da área actual (Checkpoint.cs — ex: início de
    ///    área, Caminho do Ferimento), se existir.
    /// 2) Último Refúgio Seguro permanente (SafeHaven cujo "safeHavenId"
    ///    corresponda a PlayerProgress.lastCheckpointId).
    /// 3) Início da área: primeiro AreaSpawnPoint que corresponda ao primeiro
    ///    spawnPointId do AreaData actual (entrada perto do portal para a Terra de
    ///    Gaia). Se não houver correspondência, usa qualquer AreaSpawnPoint da cena.
    ///    GDD: Íris NUNCA deve reaparecer exactamente onde morreu — sem fallback
    ///    para a posição de morte.
    /// </summary>
    private bool ResolveCheckpointPosition(out Vector2 position)
    {
        var progress = PlayerProgress.Instance;

        var currentArea = WorldState.Instance != null ? WorldState.Instance.CurrentArea : null;
        string currentAreaId = currentArea != null ? currentArea.areaId : null;

        // 1) Checkpoint temporário da área.
        if (progress != null && progress.TryGetTemporaryCheckpoint(currentAreaId, out position))
            return true;

        // 2) Último Refúgio Seguro (SafeHaven) — usa lista estática em vez de FindObjectsOfType.
        string checkpointId = progress != null ? progress.lastCheckpointId : null;
        if (!string.IsNullOrEmpty(checkpointId))
        {
            foreach (var haven in SafeHaven.All)
            {
                if (haven == null || haven.safeHavenId != checkpointId) continue;

                position = haven.transform.position;
                return true;
            }
        }

        // 3) Início da área: entrada principal (primeiro spawnPointId do AreaData,
        //    ou qualquer AreaSpawnPoint na cena — nunca o local de morte).
        //    GDD: Íris não pode reaparecer onde morreu.
        //    Usa lista estática em vez de FindObjectsOfType.
        var spawnPoints = AreaSpawnPoint.All;
        if (spawnPoints.Count > 0)
        {
            // Preferir o ponto que corresponda ao primeiro spawnPointId da área.
            string preferredId = currentArea != null &&
                                 currentArea.spawnPointIds != null &&
                                 currentArea.spawnPointIds.Count > 0
                ? currentArea.spawnPointIds[0]
                : null;

            if (!string.IsNullOrEmpty(preferredId))
            {
                foreach (var sp in spawnPoints)
                {
                    if (sp != null && sp.spawnId == preferredId)
                    {
                        position = sp.transform.position;
                        return true;
                    }
                }
            }

            // Fallback: qualquer AreaSpawnPoint na cena.
            if (spawnPoints[0] != null)
            {
                position = spawnPoints[0].transform.position;
                return true;
            }
        }

        // Nenhum ponto encontrado — mantém posição actual (caso extremo: área sem
        // AreaSpawnPoint, SafeHaven ou checkpoint configurado).
        position = default;
        return false;
    }

    /// <summary>
    /// Reset selectivo ao reaparecer ("boss reset" + "reset selectivo
    /// preservando puzzles/NPCs concluídos"): repõe à posição/vida inicial
    /// todos os <see cref="EnemyMultiPartBoss"/> (via ResetParts +
    /// ResetEnemy de cada parte, se tiverem EnemyPuzzleInteraction/EnemyRespawn)
    /// e todos os <see cref="EnemyRespawn"/> em modo "Comum" da cena actual.
    ///
    /// Inimigos "Especiais"/MiniBoss derrotados permanentemente (IsPermanent)
    /// NÃO são repostos — continuam registados em
    /// PlayerProgress.defeatedEnemyIds. Variáveis globais (puzzles resolvidos,
    /// NPCs resgatados) também não são tocadas — preservadas tal como estão.
    /// </summary>
    private void ResetSceneEnemies()
    {
        foreach (var respawn in EnemyRespawn.All)
        {
            if (respawn == null || respawn.mode != EnemyRespawnMode.Comum) continue;
            respawn.ResetEnemy();
        }

        var bosses = FindObjectsByType<EnemyMultiPartBoss>(FindObjectsSortMode.None);
        foreach (var boss in bosses)
        {
            if (boss == null) continue;

            boss.ResetParts();

            foreach (var part in boss.parts)
            {
                if (part == null) continue;

                var partRespawn = part.GetComponent<EnemyRespawn>();
                if (partRespawn != null && partRespawn.mode == EnemyRespawnMode.Comum)
                {
                    partRespawn.ResetEnemy();
                    continue;
                }

                var puzzleInteraction = part.GetComponent<EnemyPuzzleInteraction>();
                puzzleInteraction?.ResetEnemy();
            }
        }
    }

    /// <summary>
    /// Reposiciona o player no checkpoint actual (sem sequência de morte —
    /// sem animação/SFX/contagem de mortes/reset de inimigos). Usado por zonas
    /// de queda não-letais (ex: FallResetZone).
    /// </summary>
    public void TeleportToCheckpoint()
    {
        if (ResolveCheckpointPosition(out Vector2 position))
        {
            rb.position = position;
            rb.linearVelocity = Vector2.zero;
        }
    }
}
